export async function GET() {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)

    const contactList = await db
      .select({
        id: contacts.id,
        name: contacts.name,
        email: contacts.email,
        phone: contacts.phone,
        title: contacts.title,
        avatarUrl: contacts.avatarUrl,
        linkedinUrl: contacts.linkedinUrl,
        twitterHandle: contacts.twitterHandle,
        source: contacts.source,
        lastContactedAt: contacts.lastContactedAt,
        nextAction: contacts.nextAction,
        nextActionDate: contacts.nextActionDate,
        notes: contacts.notes,
        customFields: contacts.customFields,
        companyId: contacts.companyId,
        companyName: companies.name,
        createdAt: contacts.createdAt,
        updatedAt: contacts.updatedAt,
      })
      .from(contacts)
      .leftJoin(companies, eq(contacts.companyId, companies.id))
      .where(eq(contacts.workspaceId, workspace.id))
      .orderBy(desc(contacts.updatedAt))

    // Fetch tags for all contacts in one query
    const allContactTags = await db
      .select({
        contactId: contactTags.contactId,
        tagId: tags.id,
        tagName: tags.name,
        tagColor: tags.color,
      })
      .from(contactTags)
      .innerJoin(tags, eq(contactTags.tagId, tags.id))
      .where(eq(tags.workspaceId, workspace.id))

    // Group tags by contact
    const tagsByContact = new Map<string, { id: string; name: string; color: string | null }[]>()
    for (const ct of allContactTags) {
      const existing = tagsByContact.get(ct.contactId) || []
      existing.push({ id: ct.tagId, name: ct.tagName, color: ct.tagColor })
      tagsByContact.set(ct.contactId, existing)
