    const result = contactList.map((c) => ({
      ...c,
      tags: tagsByContact.get(c.id) || [],
    }))

    return NextResponse.json(result)
  } catch (error) {
    console.error('Error fetching contacts:', error)
    return NextResponse.json({ error: 'Failed to fetch contacts' }, { status: 500 })
  }
}

