import { auth } from '@/lib/auth'
import { db } from '@/lib/db'
import { requireWorkspace } from '@/lib/workspace'
import {
  contacts,
  companies,
  tags,
  contactTags,
  interactions,
} from '@/lib/db/schema'
import { eq, and, desc } from 'drizzle-orm'
import { NextResponse } from 'next/server'

export async function GET(
  _request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)
    const { id } = await params

    const [contact] = await db
      .select({
        id: contacts.id,
        name: contacts.name,
        email: contacts.email,
        phone: contacts.phone,
        title: contacts.title,
        avatarUrl: contacts.avatarUrl,
        linkedinUrl: contacts.linkedinUrl,
        twitterHandle: contacts.twitterHandle,
        source: contacts.source,
        lastContactedAt: contacts.lastContactedAt,
        nextAction: contacts.nextAction,
        nextActionDate: contacts.nextActionDate,
        notes: contacts.notes,
        customFields: contacts.customFields,
        companyId: contacts.companyId,
        companyName: companies.name,
        companyDomain: companies.domain,
        companyIndustry: companies.industry,
        createdAt: contacts.createdAt,
        updatedAt: contacts.updatedAt,
      })
      .from(contacts)
      .leftJoin(companies, eq(contacts.companyId, companies.id))
      .where(and(eq(contacts.id, id), eq(contacts.workspaceId, workspace.id)))
      .limit(1)

    if (!contact) {
      return NextResponse.json({ error: 'Contact not found' }, { status: 404 })
    }

    // Fetch tags for this contact
    const contactTagList = await db
      .select({
        id: tags.id,
        name: tags.name,
        color: tags.color,
      })
      .from(contactTags)
      .innerJoin(tags, eq(contactTags.tagId, tags.id))
      .where(eq(contactTags.contactId, id))

    // Fetch interactions for this contact
    const contactInteractions = await db
      .select()
      .from(interactions)
      .where(
        and(
          eq(interactions.contactId, id),
          eq(interactions.workspaceId, workspace.id)
        )
      )
      .orderBy(desc(interactions.occurredAt))

    return NextResponse.json({
      ...contact,
      tags: contactTagList,
      interactions: contactInteractions,
    })
  } catch (error) {
    console.error('Error fetching contact:', error)
    return NextResponse.json({ error: 'Failed to fetch contact' }, { status: 500 })
  }
}

export async function PUT(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)
    const { id } = await params
    const body = await request.json()

    const { tagIds, ...updateData } = body

    // Verify contact belongs to this workspace
    const [existing] = await db
      .select({ id: contacts.id })
      .from(contacts)
      .where(and(eq(contacts.id, id), eq(contacts.workspaceId, workspace.id)))
      .limit(1)

    if (!existing) {
      return NextResponse.json({ error: 'Contact not found' }, { status: 404 })
    }

    const [updated] = await db
      .update(contacts)
      .set({ ...updateData, updatedAt: new Date() })
      .where(and(eq(contacts.id, id), eq(contacts.workspaceId, workspace.id)))
      .returning()

    // Update tags if provided
    if (tagIds && Array.isArray(tagIds)) {
      // Remove existing tags
      await db.delete(contactTags).where(eq(contactTags.contactId, id))

      // Add new tags
      if (tagIds.length > 0) {
        await db.insert(contactTags).values(
          tagIds.map((tagId: string) => ({
            contactId: id,
            tagId,
          }))
        )
      }
    }

    return NextResponse.json(updated)
  } catch (error) {
    console.error('Error updating contact:', error)
    return NextResponse.json({ error: 'Failed to update contact' }, { status: 500 })
  }
}

export async function DELETE(
  _request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)
    const { id } = await params

    const [deleted] = await db
      .delete(contacts)
      .where(and(eq(contacts.id, id), eq(contacts.workspaceId, workspace.id)))
