export async function GET() {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)

    const pipelineList = await db
      .select()
      .from(pipelines)
      .where(eq(pipelines.workspaceId, workspace.id))
      .orderBy(desc(pipelines.createdAt))

    // Fetch stages for all pipelines
    const pipelineIds = pipelineList.map((p) => p.id)

    let allStages: {
      id: string
      pipelineId: string
      name: string
      color: string | null
      position: number
      createdAt: Date
    }[] = []

    if (pipelineIds.length > 0) {
      allStages = await db
        .select()
        .from(pipelineStages)
        .where(
          eq(pipelineStages.pipelineId, pipelineIds[0])
        )

      // Fetch stages for remaining pipelines
      for (let i = 1; i < pipelineIds.length; i++) {
        const stages = await db
          .select()
          .from(pipelineStages)
          .where(eq(pipelineStages.pipelineId, pipelineIds[i]))
        allStages = allStages.concat(stages)
      }
    }

    // Group stages by pipeline
    const stagesByPipeline = new Map<string, typeof allStages>()
    for (const stage of allStages) {
      const existing = stagesByPipeline.get(stage.pipelineId) || []
