import { auth } from '@/lib/auth'
import { db } from '@/lib/db'
import { requireWorkspace } from '@/lib/workspace'
import { pipelines, pipelineStages, pipelineContacts, contacts } from '@/lib/db/schema'
import { eq, and } from 'drizzle-orm'
import { NextResponse } from 'next/server'

export async function POST(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)
    const { id: pipelineId } = await params
    const body = await request.json()

    const { contactId, stageId, position, metadata } = body

    // Verify pipeline belongs to workspace
    const [pipeline] = await db
      .select({ id: pipelines.id })
      .from(pipelines)
      .where(
        and(
          eq(pipelines.id, pipelineId),
          eq(pipelines.workspaceId, workspace.id)
        )
      )
      .limit(1)

    if (!pipeline) {
      return NextResponse.json({ error: 'Pipeline not found' }, { status: 404 })
    }

    // Verify contact belongs to workspace
    const [contact] = await db
      .select({ id: contacts.id })
      .from(contacts)
      .where(
        and(
          eq(contacts.id, contactId),
          eq(contacts.workspaceId, workspace.id)
        )
      )
      .limit(1)

    if (!contact) {
      return NextResponse.json({ error: 'Contact not found' }, { status: 404 })
    }

    // Verify stage belongs to this pipeline
    const [stage] = await db
      .select({ id: pipelineStages.id })
      .from(pipelineStages)
      .where(
        and(
          eq(pipelineStages.id, stageId),
          eq(pipelineStages.pipelineId, pipelineId)
        )
      )
      .limit(1)

    if (!stage) {
      return NextResponse.json({ error: 'Stage not found in this pipeline' }, { status: 404 })
    }

    const [pipelineContact] = await db
      .insert(pipelineContacts)
      .values({
        pipelineId,
        stageId,
        contactId,
        position: position ?? 0,
        metadata: metadata ?? {},
      })
      .returning()

    return NextResponse.json(pipelineContact, { status: 201 })
