export async function PUT(
  request: Request,
  { params }: { params: Promise<{ id: string }> }
) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)
    const { id: pipelineId } = await params
    const body = await request.json()

    const { contactId, stageId, position, metadata } = body

    // Verify pipeline belongs to workspace
    const [pipeline] = await db
      .select({ id: pipelines.id })
      .from(pipelines)
      .where(
        and(
          eq(pipelines.id, pipelineId),
          eq(pipelines.workspaceId, workspace.id)
        )
      )
      .limit(1)

    if (!pipeline) {
      return NextResponse.json({ error: 'Pipeline not found' }, { status: 404 })
    }

    // Verify the new stage belongs to this pipeline
    if (stageId) {
      const [stage] = await db
        .select({ id: pipelineStages.id })
        .from(pipelineStages)
        .where(
          and(
            eq(pipelineStages.id, stageId),
            eq(pipelineStages.pipelineId, pipelineId)
          )
        )
        .limit(1)

      if (!stage) {
        return NextResponse.json(
          { error: 'Stage not found in this pipeline' },
          { status: 404 }
        )
      }
    }

    const updateData: Record<string, unknown> = {}
    if (stageId) {
      updateData.stageId = stageId
      updateData.enteredStageAt = new Date()
    }
    if (position !== undefined) updateData.position = position
    if (metadata !== undefined) updateData.metadata = metadata

    const [updated] = await db
      .update(pipelineContacts)
      .set(updateData)
      .where(
        and(
          eq(pipelineContacts.pipelineId, pipelineId),
          eq(pipelineContacts.contactId, contactId)
        )
      )
      .returning()

    if (!updated) {
      return NextResponse.json(
        { error: 'Contact not found in pipeline' },
        { status: 404 }
      )
    }

    return NextResponse.json(updated)
  } catch (error) {
    console.error('Error moving contact in pipeline:', error)
    return NextResponse.json(
      { error: 'Failed to move contact in pipeline' },
      { status: 500 }
    )
  }
}

