import { auth } from '@/lib/auth'
import { db } from '@/lib/db'
import { requireWorkspace } from '@/lib/workspace'
import {
  contacts,
  companies,
  tags,
  contactTags,
  interactions,
  pipelines,
  pipelineStages,
  pipelineContacts,
} from '@/lib/db/schema'
import { eq, and, desc, sql } from 'drizzle-orm'
import { NextResponse } from 'next/server'
import Anthropic from '@anthropic-ai/sdk'

const anthropic = new Anthropic()

const SYSTEM_PROMPT = `You are Greg, an AI relationship manager for founders. You help manage professional networks, track interactions, and maintain relationships with investors, partners, and clients.

You have access to the user's CRM data including contacts, companies, interactions, pipelines, and tags.

When the user asks you to take action, respond with a JSON block containing proposed actions. Each action should have a "type" and relevant parameters.

Available action types:
- create_contact: Create a new contact. Params: { name, email?, phone?, title?, companyId?, source?, notes? }
- update_contact: Update an existing contact. Params: { contactId, ...fieldsToUpdate }
- log_interaction: Log an interaction with a contact. Params: { contactId, type (email|call|meeting|note|linkedin|twitter|other), title, body?, occurredAt? }
- draft_email: Draft an email to a contact. Params: { contactId, subject, body }
- move_pipeline_stage: Move a contact to a different pipeline stage. Params: { pipelineId, contactId, stageId }
- add_tag: Add a tag to a contact. Params: { contactId, tagId?, tagName? }
- set_next_action: Set the next action for a contact. Params: { contactId, nextAction, nextActionDate? }

When proposing actions, wrap them in a JSON code block like:
\`\`\`actions
[{ "type": "log_interaction", "params": { "contactId": "...", "type": "meeting", "title": "Coffee chat" } }]
\`\`\`

Always be helpful, concise, and proactive about maintaining relationships. If you need more information to complete an action, ask the user.`

// POST: Send a message to the AI agent with contact context
export async function POST(request: Request) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)
    const body = await request.json()

    const { message, conversationHistory, contactId } = body

    if (!message) {
      return NextResponse.json(
        { error: 'Message is required' },
        { status: 400 }
      )
    }

    // Build context about the user's CRM data
    let context = ''

    // If a specific contact is provided, fetch their details
    if (contactId) {
      const [contact] = await db
        .select({
          id: contacts.id,
          name: contacts.name,
          email: contacts.email,
          phone: contacts.phone,
          title: contacts.title,
          source: contacts.source,
          lastContactedAt: contacts.lastContactedAt,
          nextAction: contacts.nextAction,
          nextActionDate: contacts.nextActionDate,
          notes: contacts.notes,
          companyName: companies.name,
        })
        .from(contacts)
        .leftJoin(companies, eq(contacts.companyId, companies.id))
        .where(
          and(
            eq(contacts.id, contactId),
            eq(contacts.workspaceId, workspace.id)
          )
        )
        .limit(1)

      if (contact) {
        const contactInteractions = await db
          .select({
            type: interactions.type,
            title: interactions.title,
            body: interactions.body,
            occurredAt: interactions.occurredAt,
          })
          .from(interactions)
          .where(
            and(
              eq(interactions.contactId, contactId),
              eq(interactions.workspaceId, workspace.id)
            )
          )
          .orderBy(desc(interactions.occurredAt))
          .limit(10)

        const contactTagList = await db
          .select({ name: tags.name })
          .from(contactTags)
          .innerJoin(tags, eq(contactTags.tagId, tags.id))
          .where(eq(contactTags.contactId, contactId))

        context += `\n\nCurrent contact context:\n`
        context += `Name: ${contact.name}\n`
        context += `Email: ${contact.email || 'N/A'}\n`
        context += `Title: ${contact.title || 'N/A'}\n`
        context += `Company: ${contact.companyName || 'N/A'}\n`
        context += `Source: ${contact.source || 'N/A'}\n`
        context += `Last contacted: ${contact.lastContactedAt || 'Never'}\n`
        context += `Next action: ${contact.nextAction || 'None'}\n`
        context += `Next action date: ${contact.nextActionDate || 'N/A'}\n`
        context += `Notes: ${contact.notes || 'None'}\n`
        context += `Tags: ${contactTagList.map((t) => t.name).join(', ') || 'None'}\n`

        if (contactInteractions.length > 0) {
          context += `\nRecent interactions:\n`
          for (const interaction of contactInteractions) {
            context += `- [${interaction.type}] ${interaction.title} (${interaction.occurredAt})\n`
            if (interaction.body) {
              context += `  ${interaction.body.substring(0, 200)}\n`
            }
          }
        }
      }
    } else {
      // Provide a high-level summary of the CRM
      const contactCount = await db
        .select({ count: sql<number>`count(*)` })
        .from(contacts)
        .where(eq(contacts.workspaceId, workspace.id))

      const recentContacts = await db
        .select({
          id: contacts.id,
          name: contacts.name,
          email: contacts.email,
          title: contacts.title,
          lastContactedAt: contacts.lastContactedAt,
          nextAction: contacts.nextAction,
          nextActionDate: contacts.nextActionDate,
        })
        .from(contacts)
        .where(eq(contacts.workspaceId, workspace.id))
        .orderBy(desc(contacts.updatedAt))
        .limit(10)

      const pipelineList = await db
        .select({ id: pipelines.id, name: pipelines.name })
        .from(pipelines)
        .where(eq(pipelines.workspaceId, workspace.id))

      const tagList = await db
        .select({ id: tags.id, name: tags.name })
        .from(tags)
        .where(eq(tags.workspaceId, workspace.id))

      context += `\n\nCRM Summary:\n`
      context += `Total contacts: ${contactCount[0]?.count || 0}\n`
      context += `Pipelines: ${pipelineList.map((p) => `${p.name} (${p.id})`).join(', ') || 'None'}\n`
      context += `Tags: ${tagList.map((t) => `${t.name} (${t.id})`).join(', ') || 'None'}\n`

      if (recentContacts.length > 0) {
        context += `\nRecent contacts:\n`
        for (const c of recentContacts) {
          context += `- ${c.name} (${c.id}) - ${c.email || 'no email'} - ${c.title || 'no title'}`
          if (c.nextAction) {
            context += ` | Next: ${c.nextAction}`
            if (c.nextActionDate) context += ` by ${c.nextActionDate}`
          }
          context += '\n'
        }
      }
    }

    // Build messages array
    const messages: Anthropic.MessageParam[] = []

    // Add conversation history if provided
    if (conversationHistory && Array.isArray(conversationHistory)) {
      for (const msg of conversationHistory) {
        messages.push({
          role: msg.role as 'user' | 'assistant',
          content: msg.content,
        })
      }
    }

    // Add the current message with context
    messages.push({
      role: 'user',
      content: context ? `${message}\n\n---\n${context}` : message,
    })

    const response = await anthropic.messages.create({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 2048,
      system: SYSTEM_PROMPT,
      messages,
    })

    const assistantMessage =
      response.content[0].type === 'text' ? response.content[0].text : ''

    // Parse any proposed actions from the response
    const actionsMatch = assistantMessage.match(
      /```actions\n([\s\S]*?)\n```/
    )
    let proposedActions = null
    if (actionsMatch) {
      try {
        proposedActions = JSON.parse(actionsMatch[1])
      } catch {
        // If parsing fails, leave actions as null
      }
    }

    return NextResponse.json({
      message: assistantMessage,
      proposedActions,
    })
  } catch (error) {
    console.error('Error in agent chat:', error)
    return NextResponse.json(
      { error: 'Failed to process agent request' },
      { status: 500 }
    )
  }
}

// PUT: Execute an approved action
export async function PUT(request: Request) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)
    const body = await request.json()

    const { action } = body

    if (!action || !action.type) {
      return NextResponse.json(
        { error: 'Action with type is required' },
        { status: 400 }
      )
    }

    const { type, params } = action

    switch (type) {
      case 'create_contact': {
        const [contact] = await db
          .insert(contacts)
          .values({
            workspaceId: workspace.id,
            createdBy: session.user.id,
            name: params.name,
            email: params.email,
            phone: params.phone,
            title: params.title,
            companyId: params.companyId,
            source: params.source,
            notes: params.notes,
          })
          .returning()

        return NextResponse.json({ success: true, result: contact })
      }

      case 'update_contact': {
        const { contactId, ...updateFields } = params

        const [updated] = await db
          .update(contacts)
          .set({ ...updateFields, updatedAt: new Date() })
          .where(
            and(
              eq(contacts.id, contactId),
              eq(contacts.workspaceId, workspace.id)
            )
          )
          .returning()

        if (!updated) {
          return NextResponse.json(
            { error: 'Contact not found' },
            { status: 404 }
          )
        }

        return NextResponse.json({ success: true, result: updated })
      }

      case 'log_interaction': {
        // Verify contact belongs to workspace
        const [contact] = await db
          .select({ id: contacts.id })
          .from(contacts)
          .where(
            and(
              eq(contacts.id, params.contactId),
              eq(contacts.workspaceId, workspace.id)
            )
          )
          .limit(1)

        if (!contact) {
          return NextResponse.json(
            { error: 'Contact not found' },
            { status: 404 }
          )
        }

        const [interaction] = await db
          .insert(interactions)
          .values({
            workspaceId: workspace.id,
            contactId: params.contactId,
            userId: session.user.id,
            type: params.type,
            title: params.title,
            body: params.body,
            occurredAt: params.occurredAt
              ? new Date(params.occurredAt)
              : new Date(),
          })
          .returning()

        // Update last contacted
        await db
          .update(contacts)
          .set({
            lastContactedAt: interaction.occurredAt,
            updatedAt: new Date(),
          })
          .where(eq(contacts.id, params.contactId))

        return NextResponse.json({ success: true, result: interaction })
      }

      case 'draft_email': {
        // Return the drafted email for the user to review
        const [contact] = await db
          .select({ name: contacts.name, email: contacts.email })
          .from(contacts)
          .where(
            and(
              eq(contacts.id, params.contactId),
              eq(contacts.workspaceId, workspace.id)
            )
          )
          .limit(1)

        if (!contact) {
          return NextResponse.json(
            { error: 'Contact not found' },
            { status: 404 }
          )
        }

        return NextResponse.json({
          success: true,
          result: {
            to: contact.email,
            toName: contact.name,
            subject: params.subject,
            body: params.body,
          },
        })
      }

      case 'move_pipeline_stage': {
        // Verify pipeline belongs to workspace
        const [pipeline] = await db
          .select({ id: pipelines.id })
          .from(pipelines)
          .where(
            and(
              eq(pipelines.id, params.pipelineId),
              eq(pipelines.workspaceId, workspace.id)
            )
          )
          .limit(1)

        if (!pipeline) {
          return NextResponse.json(
            { error: 'Pipeline not found' },
            { status: 404 }
          )
        }

        const [updated] = await db
          .update(pipelineContacts)
          .set({
            stageId: params.stageId,
            enteredStageAt: new Date(),
          })
          .where(
            and(
              eq(pipelineContacts.pipelineId, params.pipelineId),
              eq(pipelineContacts.contactId, params.contactId)
            )
          )
          .returning()

        if (!updated) {
          return NextResponse.json(
            { error: 'Contact not found in pipeline' },
            { status: 404 }
          )
        }

        return NextResponse.json({ success: true, result: updated })
      }

      case 'add_tag': {
        let tagId = params.tagId

        // If tagName is provided instead of tagId, find or create the tag
        if (!tagId && params.tagName) {
          const [existingTag] = await db
            .select({ id: tags.id })
            .from(tags)
            .where(
              and(
                eq(tags.workspaceId, workspace.id),
                eq(tags.name, params.tagName)
              )
            )
            .limit(1)

          if (existingTag) {
            tagId = existingTag.id
          } else {
            const [newTag] = await db
              .insert(tags)
              .values({
                workspaceId: workspace.id,
                name: params.tagName,
                color: 'gray',
              })
              .returning()
            tagId = newTag.id
          }
        }

        if (!tagId) {
          return NextResponse.json(
            { error: 'Either tagId or tagName is required' },
            { status: 400 }
          )
        }

        await db
          .insert(contactTags)
          .values({
            contactId: params.contactId,
            tagId,
          })
          .onConflictDoNothing()

        return NextResponse.json({ success: true, result: { contactId: params.contactId, tagId } })
      }

      case 'set_next_action': {
        const [updated] = await db
          .update(contacts)
          .set({
            nextAction: params.nextAction,
            nextActionDate: params.nextActionDate || null,
            updatedAt: new Date(),
          })
          .where(
            and(
              eq(contacts.id, params.contactId),
              eq(contacts.workspaceId, workspace.id)
            )
          )
          .returning()

        if (!updated) {
          return NextResponse.json(
            { error: 'Contact not found' },
            { status: 404 }
          )
        }

        return NextResponse.json({ success: true, result: updated })
      }

      default:
        return NextResponse.json(
          { error: `Unknown action type: ${type}` },
          { status: 400 }
        )
    }
  } catch (error) {
    console.error('Error executing agent action:', error)
    return NextResponse.json(
      { error: 'Failed to execute action' },
      { status: 500 }
    )
  }
}

import { auth } from '@/lib/auth'
import { db } from '@/lib/db'
import { requireWorkspace } from '@/lib/workspace'
import { pipelines, pipelineStages } from '@/lib/db/schema'
import { eq, desc, inArray } from 'drizzle-orm'
import { NextResponse } from 'next/server'

export async function GET() {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)

    const pipelineList = await db
      .select()
      .from(pipelines)
      .where(eq(pipelines.workspaceId, workspace.id))
      .orderBy(desc(pipelines.createdAt))

    // Fetch all stages for these pipelines in a single query
    const pipelineIds = pipelineList.map((p) => p.id)

    const allStages =
      pipelineIds.length > 0
        ? await db
            .select()
            .from(pipelineStages)
            .where(inArray(pipelineStages.pipelineId, pipelineIds))
            .orderBy(pipelineStages.position)
        : []

    // Group stages by pipeline
    const stagesByPipeline = new Map<string, (typeof allStages)[number][]>()
    for (const stage of allStages) {
      const existing = stagesByPipeline.get(stage.pipelineId) || []
      existing.push(stage)
      stagesByPipeline.set(stage.pipelineId, existing)
    }

    const result = pipelineList.map((p) => ({
      ...p,
      stages: stagesByPipeline.get(p.id) || [],
    }))

    return NextResponse.json(result)
  } catch (error) {
    console.error('Error fetching pipelines:', error)
    return NextResponse.json({ error: 'Failed to fetch pipelines' }, { status: 500 })
  }
}

export async function POST(request: Request) {
  try {
    const session = await auth()
    if (!session?.user?.id) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 })
    }

    const workspace = await requireWorkspace(session.user.id)
    const body = await request.json()

    const { stages: stageData, ...pipelineData } = body

    const [pipeline] = await db
      .insert(pipelines)
      .values({
        ...pipelineData,
        workspaceId: workspace.id,
      })
      .returning()

    // Create stages if provided
    let createdStages: (typeof pipelineStages.$inferSelect)[] = []

    if (stageData && Array.isArray(stageData) && stageData.length > 0) {
      createdStages = await db
        .insert(pipelineStages)
        .values(
          stageData.map(
            (stage: { name: string; color?: string; position?: number }, index: number) => ({
              pipelineId: pipeline.id,
              name: stage.name,
              color: stage.color || 'gray',
              position: stage.position ?? index,
            })
          )
        )
        .returning()
    }

    return NextResponse.json(
      { ...pipeline, stages: createdStages },
      { status: 201 }
    )
  } catch (error) {
    console.error('Error creating pipeline:', error)
    return NextResponse.json({ error: 'Failed to create pipeline' }, { status: 500 })
  }
}
